-- ============================================================
-- Data Scientist roadmap seed
-- Generated from deep roadmap prompt using fixed-v12 baseline rules.
-- ============================================================
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource_map;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- Clean previous copy of this specific roadmap only.
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title = 'Data Scientist Roadmap'
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title = 'Data Scientist Roadmap'
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title = 'Data Scientist Roadmap'
);

DELETE FROM public.roadmap
WHERE title = 'Data Scientist Roadmap';

VALUES (
    'Data Scientist',
    'data-scientist',
    'A practical roadmap for CS students moving from analysis and statistics into machine learning, experimentation, reproducible research, communication, and portfolio-ready data science projects.',
    'Data',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'data-scientist'
), inserted_roadmap AS (
    SELECT
        career_role_id,
        'Data Scientist Roadmap',
        'A practical roadmap for CS students moving from analysis and statistics into machine learning, experimentation, reproducible research, communication, and portfolio-ready data science projects.',
        'template',
        'static',
        'public'
    FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT
        roadmap_id,
        1,
        'published',
        'Data Scientist Roadmap v1',
        'A curated static roadmap for CS students with phases, topics, checkpoints, projects, direct skills, resources, and validation-safe persisted mappings.',
        406,
        'none',
        '{"source":"deep-roadmap-generation-prompt-data-scientist-database-engineer-sre","version":"v1","baseline":"fixed-v12"}'::jsonb,
        'TB',
        'manual',
        now()
    FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Local skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;


('data-scientist-data-analysis', 'Data Science Analysis', 'Data & Analytics', 'Turning raw data into validated findings through framing, preparation, exploration, visualization, and interpretation.'),
('data-scientist-fastapi', 'FastAPI for Data Products', 'Backend', 'Building lightweight Python APIs that expose model outputs, analytical services, validation rules, and clear response contracts.'),
('data-scientist-forecasting', 'Forecasting for Data Science', 'Data & Analytics', 'Modeling time-dependent patterns, comparing forecast error, and explaining uncertainty in future outcomes.'),
('data-scientist-jupyter-notebooks', 'Notebook Reproducibility', 'Tools & Workflow', 'Structuring notebooks with repeatable execution, clear narrative, versioned outputs, and handoff-friendly documentation.'),
('data-scientist-machine-learning', 'Applied Machine Learning', 'AI & Machine Learning', 'Training, evaluating, comparing, and communicating supervised learning models for practical data science problems.'),
('data-scientist-matplotlib', 'Analytical Visualization with Matplotlib', 'Data & Analytics', 'Creating clear charts that reveal distributions, relationships, uncertainty, and model behavior in analysis workflows.'),
('data-scientist-mlflow', 'MLflow Experiment Tracking', 'AI & Machine Learning', 'Tracking model runs, parameters, metrics, artifacts, and versions so experiments can be compared and reproduced.'),
('data-scientist-model-calibration', 'Model Calibration', 'AI & Machine Learning', 'Checking whether predicted probabilities match observed outcomes and tuning thresholds for decision use cases.'),
('data-scientist-model-interpretability', 'Model Interpretability', 'AI & Machine Learning', 'Explaining model behavior with feature effects, diagnostics, limitations, and stakeholder-friendly evidence.'),
('data-scientist-model-monitoring', 'Model Monitoring', 'AI & Machine Learning', 'Tracking data drift, prediction quality, performance changes, and operational signals after model deployment.'),
('data-scientist-natural-language-processing', 'Natural Language Processing', 'AI & Machine Learning', 'Preparing and modeling text data with tokenization, representations, evaluation, and interpretation for data science use cases.'),
('data-scientist-neural-networks', 'Neural Network Fundamentals', 'AI & Machine Learning', 'Understanding neural network layers, activations, training behavior, overfitting, and evaluation limits.'),
('data-scientist-probability', 'Probability for Data Science', 'Mathematics & Theory', 'Using probability, distributions, expected value, and uncertainty to reason about noisy data and model assumptions.'),
('data-scientist-regression-analysis', 'Regression Modeling for Data Science', 'Data & Analytics', 'Fitting, diagnosing, and interpreting regression models while checking assumptions, errors, and practical meaning.'),
('data-scientist-technical-writing', 'Data Science Technical Writing', 'Career & Communication', 'Documenting analytical methods, assumptions, evidence, limitations, and recommendations clearly for technical and non-technical readers.'),
('data-scientist-text-preprocessing', 'Text Preprocessing for NLP', 'AI & Machine Learning', 'Cleaning, tokenizing, normalizing, and representing text data before modeling or exploratory language analysis.');

SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    category = EXCLUDED.category,
    description = EXCLUDED.description,
    is_active = true,
    updated_at = now();

-- Learning resources.
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;

SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM (
    SELECT DISTINCT ON (url) title, url, resource_type, description, provider, difficulty_level
    FROM seed_resource
    ORDER BY url, resource_key
) sr
WHERE NOT EXISTS (SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url);

DROP TABLE IF EXISTS seed_resource_map;
CREATE TEMP TABLE seed_resource_map AS
SELECT sr.resource_key, lr.learning_resource_id
FROM seed_resource sr
JOIN (
    SELECT DISTINCT ON (url) learning_resource_id, url
    FROM public.learning_resource
    ORDER BY url, created_at DESC, learning_resource_id
) lr ON lr.url = sr.url;

-- Roadmap nodes.
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    reason text,
    layout_role text NOT NULL,
    layout_group text,
    layout_rank int,
    layout_order int NOT NULL,
    estimated_hours int,
    difficulty_level text,
    priority int NOT NULL,
    position_x numeric(10,2),
    position_y numeric(10,2),
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;


SELECT
    sn.node_id, m.roadmap_version_id, parent.node_id, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.reason, sn.order_index, sn.layout_role, sn.layout_group, sn.layout_rank, sn.layout_order, sn.estimated_hours, sn.difficulty_level, sn.priority, sn.position_x, sn.position_y, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    position_x = EXCLUDED.position_x,
    position_y = EXCLUDED.position_y,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

