VALUES
('ph-data-science-role-and-workflow', NULL, 1, 'phase', NULL, NULL, NULL, 'Data Science Role and Workflow', 'This stage builds the data science role and workflow layer of the Data Scientist path.', 'Phase grouping for Data Science Role and Workflow.', 'trunk', 'roadmap-main', 1, 1, NULL, NULL, 100, 500, 1130, '{"role":"data-scientist","nodeKey":"ph-data-science-role-and-workflow"}'::jsonb, true, false, '["Data Science Role and Workflow"]'::jsonb, '["Required child nodes in this phase are completed."]'::jsonb),
('data-science-problem-framing', 'grp-data-science-role-and-workflow-foundations', 1, 'topic', NULL, NULL, NULL, 'Data Science Problem Framing', 'Practice data science problem framing through concrete analysis tasks, validation checks, interpretation, and communication of limitations.', 'Core topic in Data Science Role and Workflow.', 'side', 'grp-data-science-role-and-workflow-foundations-support', 1, 1, 4, 'beginner', 70, 300, 1170, '{"role":"data-scientist","nodeKey":"data-science-problem-framing"}'::jsonb, true, true, '["Explain data science problem framing using concrete examples.","Apply data science problem framing to a realistic Data Scientist task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates data science problem framing with reviewable evidence."]'::jsonb),
('analytical-questions-and-success-metrics', 'grp-data-science-role-and-workflow-foundations', 2, 'topic', NULL, NULL, NULL, 'Analytical Questions and Success Metrics', 'Frame analytical questions, define success metrics, connect them to product or business decisions, and identify what data is needed to answer them.', 'Core topic in Data Science Role and Workflow.', 'choice', 'grp-data-science-role-and-workflow-foundations-topics', 1, 2, 4, 'beginner', 70, 700, 1170, '{"role":"data-scientist","nodeKey":"analytical-questions-and-success-metrics"}'::jsonb, true, true, '["Translate a vague stakeholder request into measurable analytical questions.", "Select success metrics that reflect decision goals and known constraints."]'::jsonb, '["A written question-and-metric brief links goals, metrics, data sources, assumptions, and risks."]'::jsonb),
('data-science-lifecycle', 'grp-data-science-role-and-workflow-foundations', 3, 'topic', NULL, NULL, NULL, 'Data Science Lifecycle', 'Practice data science lifecycle through concrete analysis tasks, validation checks, interpretation, and communication of limitations.', 'Core topic in Data Science Role and Workflow.', 'choice', 'grp-data-science-role-and-workflow-foundations-topics', 1, 3, 4, 'beginner', 70, 300, 1280, '{"role":"data-scientist","nodeKey":"data-science-lifecycle"}'::jsonb, true, true, '["Explain data science lifecycle using concrete examples.","Apply data science lifecycle to a realistic Data Scientist task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates data science lifecycle with reviewable evidence."]'::jsonb),
('stakeholder-communication-for-data-science', 'grp-data-science-role-and-workflow-foundations', 4, 'topic', NULL, NULL, NULL, 'Stakeholder Communication for Data Science', 'Turn analysis results into a clear narrative with context, evidence, limitations, and actionable recommendations.', 'Core topic in Data Science Role and Workflow.', 'side', 'grp-data-science-role-and-workflow-foundations-support', 1, 4, 4, 'beginner', 70, 700, 1280, '{"role":"data-scientist","nodeKey":"stakeholder-communication-for-data-science"}'::jsonb, true, true, '["Explain stakeholder communication for data science using concrete examples.","Apply stakeholder communication for data science to a realistic Data Scientist task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates stakeholder communication for data science with reviewable evidence."]'::jsonb),
('decision-support-vs-prediction-work', 'grp-data-science-role-and-workflow-core-practice', 1, 'topic', NULL, NULL, NULL, 'Decision Support vs Prediction Work', 'Practice decision support vs prediction work through concrete analysis tasks, validation checks, interpretation, and communication of limitations.', 'Core topic in Data Science Role and Workflow.', 'side', 'grp-data-science-role-and-workflow-core-practice-support', 1, 1, 4, 'beginner', 70, 300, 1290, '{"role":"data-scientist","nodeKey":"decision-support-vs-prediction-work"}'::jsonb, true, true, '["Explain decision support vs prediction work using concrete examples.","Apply decision support vs prediction work to a realistic Data Scientist task."]'::jsonb, '["Notes, code, query, diagram, or report demonstrates decision support vs prediction work with reviewable evidence."]'::jsonb),
