('chk-data-science-role-and-workflow-review', 'grp-data-science-role-and-workflow-core-practice', 3, 'checkpoint', 'review', NULL, NULL, 'Data Science Role and Workflow Review', 'Review checkpoint for Problem Framing and Delivery Practice. The learner synthesizes completed topics such as Decision Support vs Prediction Work, Notebook Hygiene and Analysis Narratives, Assumption and Risk Log, records evidence, and updates the learning plan before continuing.', 'This checkpoint turns the phase boundary into a reflection and evidence-review step for the data science roadmap rather than another unchecked content topic.', 'checkpoint', 'grp-data-science-role-and-workflow-core-practice-checkpoints', 1, 1, 2, 'intermediate', 65, 500, 1410, '{"role": "data-scientist", "nodeKey": "chk-data-science-role-and-workflow-review", "checkpointPurpose": "phase_review", "reviewMode": "review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Explain how topics from Problem Framing and Delivery Practice connect to realistic data science work.", "Select evidence that shows attempted practice, reasoning, or implementation decisions.", "Identify which topics need review before moving to later roadmap areas."]'::jsonb, '["Write a concise review of the main ideas from this segment.", "Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.", "Record open questions, weak areas, or follow-up actions.", "Mark the checkpoint complete only after the review artifact and next steps are captured."]'::jsonb),
('ph-python-sql-and-notebook-workflow', NULL, 2, 'phase', NULL, NULL, NULL, 'Python, SQL, and Notebook Workflow', 'This stage builds the python, sql, and notebook workflow layer of the Data Scientist path.', 'Phase grouping for Python, SQL, and Notebook Workflow.', 'trunk', 'roadmap-main', 2, 2, NULL, NULL, 100, 500, 1710, '{"role":"data-scientist","nodeKey":"ph-python-sql-and-notebook-workflow"}'::jsonb, true, false, '["Python, SQL, and Notebook Workflow"]'::jsonb, '["Required child nodes in this phase are completed."]'::jsonb),
