('decision-delivery-review', 'grp-decision-delivery-and-stakeholder-evidence', 4, 'checkpoint', 'review', NULL, NULL, 'Decision Delivery Review', 'Review checkpoint for Decision Delivery and Stakeholder Evidence. The learner synthesizes completed topics such as Decision Memo Structure, Uncertainty Communication, Model Result Presentation, records evidence, and updates the learning plan before continuing.', 'This checkpoint turns the phase boundary into a reflection and evidence-review step for the data science roadmap rather than another unchecked content topic.', 'checkpoint', 'grp-decision-delivery-and-stakeholder-evidence-checkpoints', 3, 4, 2, 'intermediate', 85, 500, 6430, '{"addedIn": "v19-depth-expansion", "nodeKey": "decision-delivery-review", "checkpointPurpose": "phase_review", "reviewMode": "review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Explain how topics from Decision Delivery and Stakeholder Evidence connect to realistic data science work.", "Select evidence that shows attempted practice, reasoning, or implementation decisions.", "Identify which topics need review before moving to later roadmap areas."]'::jsonb, '["Write a concise review of the main ideas from this segment.", "Include one evidence artifact such as notes, a diagram, lab output, code, query results, screenshots, or a project review.", "Record open questions, weak areas, or follow-up actions.", "Mark the checkpoint complete only after the review artifact and next steps are captured."]'::jsonb),
('experiment-reproducibility-checklist', 'grp-reproducibility-ethics-and-production-awareness-foundations', 5, 'topic', NULL, NULL, NULL, 'Experiment Reproducibility Checklist', 'Track code version, data version, parameters, metrics, random seeds, and environment information.', 'Experiment Reproducibility Checklist adds concrete role depth and learner-visible progression.', 'choice', 'grp-reproducibility-ethics-and-production-awareness-foundations-topics', 10, 5, 3, 'intermediate', 60, 150, 6520, '{"addedIn": "v19-depth-expansion", "nodeKey": "experiment-reproducibility-checklist"}'::jsonb, true, true, '["Explain and apply experiment reproducibility checklist in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for experiment reproducibility checklist."]'::jsonb),
('data-and-model-drift-signals', 'grp-reproducibility-ethics-and-production-awareness-foundations', 6, 'topic', NULL, NULL, NULL, 'Data and Model Drift Signals', 'Identify input drift, prediction drift, and performance drift signals for deployed data products.', 'Data and Model Drift Signals adds concrete role depth and learner-visible progression.', 'choice', 'grp-reproducibility-ethics-and-production-awareness-foundations-topics', 10, 6, 3, 'intermediate', 60, 390, 6520, '{"addedIn": "v19-depth-expansion", "nodeKey": "data-and-model-drift-signals"}'::jsonb, true, true, '["Explain and apply data and model drift signals in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for data and model drift signals."]'::jsonb),
('model-card-and-limitation-notes', 'grp-reproducibility-ethics-and-production-awareness-core-practice', 5, 'topic', NULL, NULL, NULL, 'Model Card and Limitation Notes', 'Document intended use, limitations, evaluation slices, fairness concerns, and monitoring expectations.', 'Model Card and Limitation Notes adds concrete role depth and learner-visible progression.', 'choice', 'grp-reproducibility-ethics-and-production-awareness-core-practice-topics', 10, 5, 3, 'intermediate', 60, 150, 6640, '{"addedIn": "v19-depth-expansion", "nodeKey": "model-card-and-limitation-notes"}'::jsonb, true, true, '["Explain and apply model card and limitation notes in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for model card and limitation notes."]'::jsonb),
('grp-capstone-evidence-and-presentation', 'ph-portfolio-capstone', 21, 'choice_group', NULL, 'complete_all', NULL, 'Capstone Evidence and Presentation', 'Capstone Evidence and Presentation adds baseline-style detail under Portfolio Capstone.', 'Capstone Evidence and Presentation groups related required learning units inside the phase.', 'side', 'ph-portfolio-capstone-groups', 21, 21, NULL, NULL, 55, 300, 8850, '{"addedIn": "v19-depth-expansion", "nodeKey": "grp-capstone-evidence-and-presentation"}'::jsonb, true, false, '["Capstone Evidence and Presentation"]'::jsonb, '["Complete all required child nodes in this group."]'::jsonb),
('capstone-scope-and-success-criteria', 'grp-capstone-evidence-and-presentation', 1, 'topic', NULL, NULL, NULL, 'Capstone Scope and Success Criteria', 'Define a capstone question, decision audience, deliverables, metric, and evidence checklist.', 'Capstone Scope and Success Criteria adds concrete role depth and learner-visible progression.', 'choice', 'grp-capstone-evidence-and-presentation-topics', 21, 1, 3, 'intermediate', 60, 150, 9030, '{"addedIn": "v19-depth-expansion", "nodeKey": "capstone-scope-and-success-criteria"}'::jsonb, true, true, '["Explain and apply capstone scope and success criteria in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for capstone scope and success criteria."]'::jsonb),
('portfolio-narrative-and-tradeoffs', 'grp-capstone-evidence-and-presentation', 2, 'topic', NULL, NULL, NULL, 'Portfolio Narrative and Tradeoffs', 'Explain technical decisions, rejected alternatives, assumptions, and learning outcomes in a portfolio case study.', 'Portfolio Narrative and Tradeoffs adds concrete role depth and learner-visible progression.', 'choice', 'grp-capstone-evidence-and-presentation-topics', 21, 2, 3, 'intermediate', 60, 390, 9030, '{"addedIn": "v19-depth-expansion", "nodeKey": "portfolio-narrative-and-tradeoffs"}'::jsonb, true, true, '["Explain and apply portfolio narrative and tradeoffs in a role-specific workflow."]'::jsonb, '["Produce notes, code, configuration, or analysis evidence for portfolio narrative and tradeoffs."]'::jsonb),
('capstone-presentation-review', 'grp-capstone-evidence-and-presentation', 3, 'checkpoint', 'review', NULL, NULL, 'Capstone Presentation Review', 'Final roadmap checkpoint for Capstone Evidence and Presentation. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the data science path.', 'This checkpoint closes the suggested data science orientation path by organizing evidence and next steps. It is not an employment guarantee or formal competency certification.', 'checkpoint', 'grp-capstone-evidence-and-presentation-checkpoints', 21, 3, 2, 'intermediate', 85, 500, 9165, '{"addedIn": "v19-depth-expansion", "nodeKey": "capstone-presentation-review", "checkpointPurpose": "phase_review", "reviewMode": "final_review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent data science learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb);
